import pull from "../../../../../../../../../../../subject_repositories/pull-stream/pull.js"

describe("pull", () => {
  it("should correctly apply partial pipeline with multiple through streams", () => {
    function values(arr: number[]) {
      let i = 0;
      return function(end: any, cb: Function) {
        if (end) return cb(end);
        if (i >= arr.length) return cb(true);
        cb(null, arr[i++]);
      };
    }

    function map(fn: (x: number) => number) {
      return function(read: Function) {
        return function(end: any, cb: Function) {
          read(end, function(end: any, data: any) {
            if (end) return cb(end);
            cb(null, fn(data));
          });
        };
      };
    }

    // This creates a partial pipeline - pull is called with 2 args, each has .length === 1
    // So length === 2, a.length === 1, triggers partial application path
    const partial = pull(map(x => x * 3), map(x => x - 1));

    const results: number[] = [];

    // Apply the partial pipeline
    const stream = partial(values([2, 4, 6]));

    function drain(read: Function, cb: (results: number[]) => void) {
      const acc: number[] = [];
      function next() {
        read(null, function(end: any, data: any) {
          if (end === true) return cb(acc);
          if (end) throw end;
          acc.push(data);
          next();
        });
      }
      next();
    }

    drain(stream, (res) => {
      results.push(...res);
    });

    expect(results).toEqual([5, 11, 17]);
  });
});
